---
## JavaScript (Browser) - Global Feed with Infinite Scroll

```javascript
class ProductDiscoveryFeed {
  constructor() {
    this.products = [];
    this.nextCursor = null;
    this.hasMore = true;
    this.isLoading = false;
    this.baseUrl = 'http://localhost:8000/api';
  }

  async fetchGlobalFeed(limit = 20) {
    if (this.isLoading) return;
    if (!this.hasMore) return;

    this.isLoading = true;
    try {
      const url = new URL(`${this.baseUrl}/products`);
      url.searchParams.set('status', 'ACTIVE');
      url.searchParams.set('limit', limit);

      if (this.nextCursor) {
        url.searchParams.set('cursor', this.nextCursor);
      }

      const response = await fetch(url);
      const data = await response.json();

      // Append new items to list
      this.products.push(...data.items);
      this.nextCursor = data.nextCursor;
      this.hasMore = data.hasMore;

      this.renderProducts();
    } catch (error) {
      console.error('Failed to fetch products:', error);
    } finally {
      this.isLoading = false;
    }
  }

  async fetchLocationFeed(latitude, longitude, radiusKm = 25, limit = 20) {
    if (this.isLoading) return;
    if (!this.hasMore) return;

    this.isLoading = true;
    try {
      const url = new URL(`${this.baseUrl}/products`);
      url.searchParams.set('status', 'ACTIVE');
      url.searchParams.set('locationLat', latitude);
      url.searchParams.set('locationLng', longitude);
      url.searchParams.set('radiusKm', radiusKm);
      url.searchParams.set('limit', limit);

      if (this.nextCursor) {
        url.searchParams.set('cursor', this.nextCursor);
      }

      const response = await fetch(url);
      const data = await response.json();

      this.products.push(...data.items);
      this.nextCursor = data.nextCursor;
      this.hasMore = data.hasMore;

      this.renderProducts();
    } catch (error) {
      console.error('Failed to fetch location products:', error);
    } finally {
      this.isLoading = false;
    }
  }

  renderProducts() {
    const container = document.getElementById('products-container');
    container.innerHTML = this.products.map(product => `
      <div class="product-card">
        <img src="${product.images[0]?.url}" alt="${product.title}">
        <h3>${product.title}</h3>
        <p>${product.description}</p>
        <span class="location">${product.locationName}</span>
      </div>
    `).join('');
  }

  setupInfiniteScroll() {
    const observer = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting && this.hasMore && !this.isLoading) {
        // Choose global or location-based fetch
        this.fetchGlobalFeed();
        // OR for location:
        // this.fetchLocationFeed(userLat, userLng);
      }
    });

    const sentinel = document.getElementById('scroll-sentinel');
    observer.observe(sentinel);
  }
}

// Usage
const feed = new ProductDiscoveryFeed();
await feed.fetchGlobalFeed();
feed.setupInfiniteScroll();
```

