## React Hooks - Product Discovery Hook

```javascript
import { useState, useEffect, useCallback } from 'react';

function useProductDiscovery() {
  const [products, setProducts] = useState([]);
  const [cursor, setCursor] = useState(null);
  const [hasMore, setHasMore] = useState(true);
  const [isLoading, setIsLoading] = useState(false);

  const fetchGlobalFeed = useCallback(async () => {
    if (isLoading && !hasMore) return;

    setIsLoading(true);
    try {
      const url = new URL('http://localhost:8000/api/products');
      url.searchParams.set('status', 'ACTIVE');
      url.searchParams.set('limit', '20');
      if (cursor) url.searchParams.set('cursor', cursor);

      const response = await fetch(url);
      const data = await response.json();

      setProducts(prev => [...prev, ...data.items]);
      setCursor(data.nextCursor);
      setHasMore(data.hasMore);
    } finally {
      setIsLoading(false);
    }
  }, [cursor, isLoading, hasMore]);

  const fetchLocationFeed = useCallback(
    async (latitude, longitude, radiusKm = 25) => {
      if (isLoading && !hasMore) return;

      setIsLoading(true);
      try {
        const url = new URL('http://localhost:8000/api/products');
        url.searchParams.set('status', 'ACTIVE');
        url.searchParams.set('locationLat', latitude);
        url.searchParams.set('locationLng', longitude);
        url.searchParams.set('radiusKm', radiusKm);
        url.searchParams.set('limit', '20');
        if (cursor) url.searchParams.set('cursor', cursor);

        const response = await fetch(url);
        const data = await response.json();

        setProducts(prev => [...prev, ...data.items]);
        setCursor(data.nextCursor);
        setHasMore(data.hasMore);
      } finally {
        setIsLoading(false);
      }
    },
    [cursor, isLoading, hasMore]
  );

  return {
    products,
    hasMore,
    isLoading,
    fetchGlobalFeed,
    fetchLocationFeed,
    reset: () => {
      setProducts([]);
      setCursor(null);
      setHasMore(true);
    }
  };
}

// Usage in component
function DiscoveryFeed() {
  const { products, hasMore, isLoading, fetchGlobalFeed } = useProductDiscovery();
  const observerTarget = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting && hasMore && !isLoading) {
        fetchGlobalFeed();
      }
    });

    if (observerTarget.current) {
      observer.observe(observerTarget.current);
    }

    return () => observer.disconnect();
  }, [hasMore, isLoading, fetchGlobalFeed]);

  useEffect(() => {
    fetchGlobalFeed();
  }, []);

  return (
    <div>
      {products.map(product => (
        <ProductCard key={product.id} product={product} />
      ))}
      {isLoading && <Spinner />}
      <div ref={observerTarget} />
    </div>
  );
}
```

